import sysfrom pathlib import Pathimport jsonimport refrom collections import Counterimport joblibimport numpy as npimport pandas as pdfrom gensim.models import Word2Vecfrom sklearn.decomposition import PCAfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import (    accuracy_score,    classification_report,    confusion_matrix,    f1_score,)# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    EMBEDDINGS_DIR,    BASELINE_MODELS_DIR,    REPORTS_DIR,    TABLE_DIR,    INTERIM_DATA_DIR,)DATASET_TAG = "small_full"TEXT_COL = "full_text"LABEL_COL = "label_5d"MIN_TOKEN_LEN = 2SIF_A = 1e-3def simple_tokenize(text: str):    text = str(text).lower()    tokens = re.findall(r"[a-zA-Z0-9]+", text)    tokens = [tok for tok in tokens if len(tok) >= MIN_TOKEN_LEN]    return tokensdef load_data():    train_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d.parquet")    val_df = pd.read_parquet(PROCESSED_DATA_DIR / "validation_doc_5d.parquet")    test_df = pd.read_parquet(PROCESSED_DATA_DIR / "test_doc_5d.parquet")    return train_df, val_df, test_dfdef load_word2vec():    model_path = EMBEDDINGS_DIR / f"word2vec_{DATASET_TAG}.model"    if not model_path.exists():        raise FileNotFoundError(f"Word2Vec model not found: {model_path}")    model = Word2Vec.load(str(model_path))    return modeldef compute_word_frequencies(tokenized_docs):    counter = Counter()    total_tokens = 0    for tokens in tokenized_docs:        counter.update(tokens)        total_tokens += len(tokens)    if total_tokens == 0:        return {}    word_freq = {word: count / total_tokens for word, count in counter.items()}    return word_freqdef document_to_vector_sif(tokens, w2v_model, word_freq, a=SIF_A):    vectors = []    weights = []    for tok in tokens:        if tok in w2v_model.wv and tok in word_freq:            vectors.append(w2v_model.wv[tok])            weights.append(a / (a + word_freq[tok]))    if len(vectors) == 0:        return np.zeros(w2v_model.vector_size, dtype=np.float32)    vectors = np.vstack(vectors)    weights = np.array(weights, dtype=np.float32).reshape(-1, 1)    weighted_avg = np.sum(weights * vectors, axis=0) / np.sum(weights)    return weighted_avg.astype(np.float32)def build_embedding_matrix(df: pd.DataFrame, w2v_model, word_freq):    tokenized_docs = df[TEXT_COL].astype(str).apply(simple_tokenize)    X = np.vstack(        [            document_to_vector_sif(tokens, w2v_model, word_freq)            for tokens in tokenized_docs        ]    ).astype(np.float32)    y = df[LABEL_COL].astype(int).values    coverage = []    for tokens in tokenized_docs:        if len(tokens) == 0:            coverage.append(0.0)        else:            in_vocab = sum(tok in w2v_model.wv for tok in tokens)            coverage.append(in_vocab / len(tokens))    return X, y, tokenized_docs.tolist(), coveragedef remove_first_principal_component(X_train, X_val, X_test):    pca = PCA(n_components=1, random_state=42)    pca.fit(X_train)    u = pca.components_[0]    X_train_new = X_train - X_train.dot(u.reshape(-1, 1)) * u    X_val_new = X_val - X_val.dot(u.reshape(-1, 1)) * u    X_test_new = X_test - X_test.dot(u.reshape(-1, 1)) * u    return (        X_train_new.astype(np.float32),        X_val_new.astype(np.float32),        X_test_new.astype(np.float32),    )def basic_data_check(df: pd.DataFrame, split_name: str):    print(f"\n--- {split_name.upper()} ---")    print("Shape:", df.shape)    print("Label distribution:")    print(df[LABEL_COL].value_counts(dropna=False).sort_index())    print(df[[TEXT_COL, LABEL_COL]].head(2))def train_classifier(X_train, y_train, X_val, y_val):    candidates = [        {"C": 0.1},        {"C": 1.0},        {"C": 10.0},    ]    best_model = None    best_result = None    all_results = []    for i, cfg in enumerate(candidates, start=1):        print(f"\nTraining candidate {i}: {cfg}")        clf = LogisticRegression(            C=cfg["C"],            max_iter=2000,            random_state=42,        )        clf.fit(X_train, y_train)        val_pred = clf.predict(X_val)        acc = accuracy_score(y_val, val_pred)        f1 = f1_score(y_val, val_pred)        result = {            "candidate_id": i,            "C": cfg["C"],            "val_accuracy": acc,            "val_f1": f1,        }        all_results.append(result)        print(f"Validation Accuracy: {acc:.4f}")        print(f"Validation F1:       {f1:.4f}")        if best_result is None or f1 > best_result["val_f1"]:            best_result = result            best_model = clf    return best_model, best_result, pd.DataFrame(all_results)def evaluate_on_test(model, X_test, y_test):    test_pred = model.predict(X_test)    test_acc = accuracy_score(y_test, test_pred)    test_f1 = f1_score(y_test, test_pred)    cm = confusion_matrix(y_test, test_pred)    clf_report = classification_report(y_test, test_pred, output_dict=True)    print("\n=== TEST PERFORMANCE ===")    print(f"Test Accuracy: {test_acc:.4f}")    print(f"Test F1:       {test_f1:.4f}")    print("Confusion Matrix:")    print(cm)    return {        "test_accuracy": test_acc,        "test_f1": test_f1,        "confusion_matrix": cm.tolist(),        "classification_report": clf_report,    }def save_outputs(    clf,    best_result,    validation_results_df,    test_results,    X_train,    X_val,    X_test,    train_coverage,    val_coverage,    test_coverage,):    BASELINE_MODELS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    INTERIM_DATA_DIR.mkdir(parents=True, exist_ok=True)    model_path = BASELINE_MODELS_DIR / f"word2vec_logistic_{DATASET_TAG}.joblib"    report_path = REPORTS_DIR / f"word2vec_logistic_{DATASET_TAG}_results.json"    val_table_path = TABLE_DIR / f"word2vec_logistic_{DATASET_TAG}_validation_results.csv"    train_embed_path = INTERIM_DATA_DIR / f"train_doc_embedding_word2vec_{DATASET_TAG}.npy"    val_embed_path = INTERIM_DATA_DIR / f"validation_doc_embedding_word2vec_{DATASET_TAG}.npy"    test_embed_path = INTERIM_DATA_DIR / f"test_doc_embedding_word2vec_{DATASET_TAG}.npy"    np.save(train_embed_path, X_train)    np.save(val_embed_path, X_val)    np.save(test_embed_path, X_test)    joblib.dump(clf, model_path)    validation_results_df.to_csv(val_table_path, index=False)    payload = {        "best_validation_result": best_result,        "test_results": test_results,        "avg_train_token_coverage": float(np.mean(train_coverage)),        "avg_validation_token_coverage": float(np.mean(val_coverage)),        "avg_test_token_coverage": float(np.mean(test_coverage)),        "sif_a": SIF_A,    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(payload, f, indent=2)    print("\nSaved outputs:")    print(model_path)    print(report_path)    print(val_table_path)    print(train_embed_path)    print(val_embed_path)    print(test_embed_path)def main():    print("Loading document-level datasets...")    train_df, val_df, test_df = load_data()    basic_data_check(train_df, "train")    basic_data_check(val_df, "validation")    basic_data_check(test_df, "test")    print("\nLoading Word2Vec model...")    w2v_model = load_word2vec()    print(f"Word2Vec vector size: {w2v_model.vector_size}")    print(f"Word2Vec vocab size:  {len(w2v_model.wv.key_to_index)}")    print("\nTokenizing training data for SIF...")    train_tokens = train_df[TEXT_COL].astype(str).apply(simple_tokenize).tolist()    print("Computing word frequencies from training set...")    word_freq = compute_word_frequencies(train_tokens)    print(f"Unique tokens with frequency entries: {len(word_freq)}")    print("\nBuilding SIF document embeddings...")    X_train, y_train, _, train_coverage = build_embedding_matrix(train_df, w2v_model, word_freq)    X_val, y_val, _, val_coverage = build_embedding_matrix(val_df, w2v_model, word_freq)    X_test, y_test, _, test_coverage = build_embedding_matrix(test_df, w2v_model, word_freq)    print(f"Train embedding shape:      {X_train.shape}")    print(f"Validation embedding shape: {X_val.shape}")    print(f"Test embedding shape:       {X_test.shape}")    print("\nAverage token coverage:")    print(f"Train:      {np.mean(train_coverage):.4f}")    print(f"Validation: {np.mean(val_coverage):.4f}")    print(f"Test:       {np.mean(test_coverage):.4f}")    print("\nRemoving first principal component (fit on train only)...")    X_train, X_val, X_test = remove_first_principal_component(X_train, X_val, X_test)    print("\nTraining Logistic Regression on SIF document embeddings...")    best_model, best_result, validation_results_df = train_classifier(        X_train, y_train, X_val, y_val    )    print("\nBest validation configuration:")    print(best_result)    test_results = evaluate_on_test(best_model, X_test, y_test)    save_outputs(        best_model,        best_result,        validation_results_df,        test_results,        X_train,        X_val,        X_test,        train_coverage,        val_coverage,        test_coverage,    )    print("\nDone.")if __name__ == "__main__":    main()